const body = $input.first().json.body || $input.first().json;

const lastDay = body.lastDay || body.last_day;
const lastDayDate = lastDay ? new Date(lastDay) : new Date();

return [{
  json: {
    employeeId: body.employeeId || body.employee_id || '',
    fullName: body.fullName || body.full_name || `${body.firstName || ''} ${body.lastName || ''}`.trim(),
    email: body.email || body.work_email || '',
    personalEmail: body.personalEmail || body.personal_email || '',
    department: body.department || '',
    managerId: body.managerId || body.manager_id || '',
    managerEmail: body.managerEmail || body.manager_email || '',
    lastDay: lastDayDate.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }),
    lastDayIso: lastDayDate.toISOString().split('T')[0],
    reason: body.reason || 'Voluntary Resignation',
    equipmentReturned: body.equipmentReturned || false,
    initiatedBy: body.initiatedBy || body.hr_name || 'HR',
    timestamp: new Date().toISOString()
  }
}];
